          ]
        }
      },

      figures: {
        type: 'array',
        items: {
          type: 'object',
          additionalProperties: false,
          properties: {
            label: { type: 'string' },
            type: { type: 'string' },
            description: { type: 'string' }
          },
          required: [
            'label',
            'type',
            'description'
          ]
        }
      },

      visual_notes: {
        type: 'array',
        items: {
          type: 'object',
          additionalProperties: false,
          properties: {
            label: { type: 'string' },
            description: { type: 'string' }
          },
          required: [
            'label',
            'description'
          ]
        }
      },

